    "fields": {
      "summary": "Build Senior Developer agent (spec-driven, human-in-the-loop)",
      "description": {
        "content": [
          {
            "content": [
              {
                "text": "Goal",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "Tackle complex tickets with a human checkpoint between exploration and implementation. Uses spec-driven development.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Deliverables",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* agents/senior-dev/prompt.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* agents/senior-dev/README.md",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* .github/workflows/senior-dev.yml — modeled on .github/workflows/jira-ticket.yml. Triggered via workflow_dispatch and/or repository_dispatch from the orchestrator.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Spec-driven flow",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "Uses /openspec:explore (named in docs/agentic-workflow.md). Confirm this skill/command is available inside anthropics/claude-code-action@v1. If not, document the substitute.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Human-in-the-loop pause",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "Between spec exploration and implementation, the workflow must wait for explicit human approval. Options:",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Write the spec to a draft PR and resume only when a human posts a magic-keyword comment.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Post the spec as a Jira comment and resume only on a transition / label.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "Pick one and document.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          },
          {
            "content": [
              {
                "text": "Acceptance criteria",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Dispatching the workflow on a complex KAN ticket produces a spec artefact and pauses.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* A human approval action resumes the workflow into implementation.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Run log committed under .github/agent-logs/senior-dev//.json.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          }
        ],
