                          {
                            "type": "code"
                          }
                        ],
                        "text": "agents/testing/prompt.md",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              },
              {
                "content": [
                  {
                    "content": [
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "agents/testing/README.md",
                        "type": "text"
                      },
                      {
                        "text": ".",
                        "type": "text"
